```bash
nl -ba llvm/lib/Analysis/InstructionSimplify.cpp | sed -n '4055,4075p' && sed -i '4069a \  // Avoid simplifying FP compares against zero when NSZ is set: such folds can
  // alter predicates around zero and expose a specific signed-zero downstream.
  if (FMF.noSignedZeros()) {
    const APFloat *ZeroC = nullptr;
    if (match(RHS, m_APFloat(ZeroC)) && ZeroC && ZeroC->isZero())
      return nullptr;
    if (match(LHS, m_APFloat(ZeroC)) && ZeroC && ZeroC->isZero())
      return nullptr;
  }' llvm/lib/Analysis/InstructionSimplify.cpp && submit-patch
```

